import { useState, useEffect } from 'react';
import Nav from '../components/Nav';
import heroImage from '../assets/gamehome.jpg';
import '../styles.css';

function HomePage() {
  const [theme, setTheme] = useState('dark');

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') || 'dark';
    setTheme(savedTheme);
    document.body.className = savedTheme === 'light' ? 'light-mode' : '';
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.body.className = newTheme === 'light' ? 'light-mode' : '';
  };

  return (
    <>
      <Nav theme={theme} toggleTheme={toggleTheme} />
      <main className="container">
        <section className="hero">
          <h2>Welcome to My Gaming World</h2>
          <p>Gaming Passion is a personal portfolio showcasing my journey from casual gaming to competitive play and esports enthusiasm.</p>
          <img src={heroImage} alt="Gamers using different gaming devices" />
        </section>

        <section className="features">
          <h3>Why I Love Gaming</h3>
          <ul>
            <li>Enhances problem-solving skills</li>
            <li>Builds teamwork and communication</li>
            <li>Develops strategic thinking</li>
            <li>Connects gamers worldwide</li>
          </ul>
        </section>

        <section className="previews">
          <div className="preview-box">
            <h3>Explore My Journey</h3>
            <p>Discover how gaming became my passion and shaped my skills.</p>
          </div>
          <div className="preview-box">
            <h3>Join the Community</h3>
            <p>Register to get gaming updates, tips, and exclusive content.</p>
          </div>
        </section>

        <footer>
          <p>Contact: gaming@email.com</p>
          <p>© 2026 Gaming Passion</p>
        </footer>
      </main>
    </>
  );
}

export default HomePage;
